// State management
const [filterDrawerOpen, setFilterDrawerOpen] = useState(false);
const [pendingFilters, setPendingFilters] = useState({
  status: [] as string[],
  priority: [] as string[],
  assignee: [] as string[]
});
const [appliedFilters, setAppliedFilters] = useState({
  status: [] as string[],
  priority: [] as string[],
  assignee: [] as string[]
});

// Filter options extracted from data
const filterOptions = useMemo(() => ({
  statuses: [...new Set(data.map(item => item.statusText))].sort(),
  priorities: ['high', 'medium', 'low'],
  assignees: [...new Set(data.map(item => item.assignedTo))].sort()
}), [data]);

// Toggle a pending filter value
const togglePendingFilter = (category: keyof typeof pendingFilters, value: string) => {
  setPendingFilters(prev => ({
    ...prev,
    [category]: prev[category].includes(value)
      ? prev[category].filter(v => v !== value)
      : [...prev[category], value]
  }));
};

// Apply pending filters
const applyFilters = () => {
  setAppliedFilters(pendingFilters);
  setFilterDrawerOpen(false);
};

// Clear all pending filters
const clearAllPending = () => {
  setPendingFilters({ status: [], priority: [], assignee: [] });
};

// JSX
<GoabDrawer
  heading="Filter items"
  position="right"
  open={filterDrawerOpen}
  maxSize="300px"
  onClose={() => setFilterDrawerOpen(false)}
  actions={
    <GoabButtonGroup alignment="start" gap="compact">
      <GoabButton type="primary" size="compact" onClick={applyFilters}>
        Apply filters
      </GoabButton>
      <GoabButton type="tertiary" size="compact" onClick={() => setFilterDrawerOpen(false)}>
        Cancel
      </GoabButton>
    </GoabButtonGroup>
  }
>
  <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-l)' }}>
    {/* Status filter */}
    <GoabFormItem label="Status">
      <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
        {filterOptions.statuses.map(status => (
          <GoabCheckbox
            key={status}
            name={`status-${status}`}
            text={status}
            checked={pendingFilters.status.includes(status)}
            onChange={() => togglePendingFilter('status', status)}
          />
        ))}
      </div>
    </GoabFormItem>

    {/* Priority filter */}
    <GoabFormItem label="Priority">
      <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
        {filterOptions.priorities.map(priority => (
          <GoabCheckbox
            key={priority}
            name={`priority-${priority}`}
            text={priority.charAt(0).toUpperCase() + priority.slice(1)}
            checked={pendingFilters.priority.includes(priority)}
            onChange={() => togglePendingFilter('priority', priority)}
          />
        ))}
      </div>
    </GoabFormItem>

    {/* Assignee filter */}
    <GoabFormItem label="Assigned to">
      <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--goa-space-xs)' }}>
        {filterOptions.assignees.map(assignee => (
          <GoabCheckbox
            key={assignee}
            name={`assignee-${assignee}`}
            text={assignee}
            checked={pendingFilters.assignee.includes(assignee)}
            onChange={() => togglePendingFilter('assignee', assignee)}
          />
        ))}
      </div>
    </GoabFormItem>

    {/* Clear all button - only shown if any pending filters selected */}
    {Object.values(pendingFilters).some(arr => arr.length > 0) && (
      <>
        <GoabDivider />
        <GoabButton type="tertiary" size="compact" onClick={clearAllPending}>
          Clear all filters
        </GoabButton>
      </>
    )}
  </div>
</GoabDrawer>
